global class LeadNurturingBatch implements Database.Batchable<SObject> {

    global Database.QueryLocator start(Database.BatchableContext bc) {
        DateTime cutoff = DateTime.now().addDays(-90);
        return Database.getQueryLocator([
            SELECT Id, Status
            FROM Lead
            WHERE Status = 'Open - Not Contacted'
            AND CreatedDate <= :cutoff
        ]);
    }

    global void execute(Database.BatchableContext bc, List<Lead> scope) {
        for (Lead l : scope) {
            l.Status = 'Nurturing';
        }
        update scope;
    }

    global void finish(Database.BatchableContext bc) {
    }
}

global class ArchiveClosedOpportunitiesJob implements Schedulable {

    global void execute(SchedulableContext sc) {
        Date cutoff = Date.today().addYears(-1);

        List<Opportunity> oppsToArchive = [
            SELECT Id, Archived__c
            FROM Opportunity
            WHERE IsClosed = true
            AND CloseDate <= :cutoff
            AND Archived__c = false
        ];

        for (Opportunity opp : oppsToArchive) {
            opp.Archived__c = true;
        }

        if (!oppsToArchive.isEmpty()) {
            update oppsToArchive;
        }
    }
}

Schedule it with, e.g.:
System.schedule('Archive Closed Opportunities - Daily', '0 0 2 * * ?', new ArchiveClosedOpportunitiesJob());

