import { LightningElement, api } from 'lwc';
import { ShowToastEvent } from 'lightning/platformShowToastEvent';
import closeAllOpenTasks from '@salesforce/apex/TaskController.closeAllOpenTasks';

export default class CloseTasksButton extends LightningElement {
    @api recordId;

    handleClick() {
        closeAllOpenTasks({ accountId: this.recordId })
            .then(() => {
                this.dispatchEvent(new ShowToastEvent({
                    title: 'Success',
                    message: 'All open tasks were closed.',
                    variant: 'success'
                }));
            })
            .catch((error) => {
                this.dispatchEvent(new ShowToastEvent({
                    title: 'Error closing tasks',
                    message: error.body?.message,
                    variant: 'error'
                }));
            });
    }
}

